function consolidate(subBalances) {
  return subBalances.reduce((acc, curr) => acc + curr, 0);
}

def can_pay(po, gr, invoice, qty_tol=0.01, price_tol=0.01):
    if abs(invoice.qty - gr.qty) / po.qty > qty_tol:
        return False, 'quantity_mismatch'
    if abs(invoice.price - po.price) / po.price > price_tol:
        return False, 'price_mismatch'
    if invoice.po_id != po.id or gr.po_id != po.id:
        return False, 'reference_mismatch'
    return True, 'ok_to_pay'

function forecastNextMonth(prevData) {
  const avg = prevData.reduce((a,b) => a+b) / prevData.length;
  return avg * 1.05; // 5% growth projection
}
